// Velocidade e área roçada (largura de corte 1.5 m)
var vel  = parseFloat((Math.random() * 1.5 + 0.5).toFixed(1));
var area = parseFloat(flow.get('area') || 0);
area = parseFloat((area + vel * 2 * 1.5).toFixed(1));
flow.set('area', area);

// Distância percorrida (vel m/s * 2 s / 1000 = km por tick)
var dist = parseFloat(flow.get('distKm') || 0);
dist = parseFloat((dist + vel * 2 / 1000).toFixed(3));
flow.set('distKm', dist);

var v = parseFloat(rand(11.1, 12.6).toFixed(2));
var i = parseFloat(rand(0.5, 7.5).toFixed(3));
msg.payload = {
    lat:     parseFloat((pt[0] + rand(-0.00003, 0.00003)).toFixed(6)),
    lon:     parseFloat((pt[1] + rand(-0.00003, 0.00003)).toFixed(6)),
    roll:    parseFloat(rand(-4, 4).toFixed(2)),
    pitch:   parseFloat(rand(-2, 2).toFixed(2)),
    yaw:     parseFloat((310 + rand(-5, 5)).toFixed(1)),
    d_front: Math.max(10, Math.round(rand(80, 400))),
    d_rear:  Math.max(10, Math.round(rand(80, 400))),
    d_left:  Math.max(5,  Math.round(rand(15, 60))),
    d_right: Math.max(5,  Math.round(rand(15, 60))),
    velocity: vel,
    area:     Math.round(area),
    voltage: v,
    current: i,
    power:      parseFloat((v * i).toFixed(2)),
    dist_km:    parseFloat(dist.toFixed(2)),
    // eficiência: largura de corte 1.5 m × vel m/s × 3600 s
    eficiencia: Math.round(vel * 1.5 * 3600),
    // custo: tarifa elétrica R$0,85/kWh + mão-de-obra/manutenção R$45/h
    custo_m2:   parseFloat(((45 + (v * i / 1000) * 0.85) / Math.max(1, vel * 1.5 * 3600)).toFixed(5)),
    rodovia:  'SP-330 — Anhanguera',
    endereco: 'Rod. Anhanguera, km ' + (70 + parseFloat((idx * 2.4 / route.length).toFixed(1))),
    cidade:   'Jundiaí',
    estado:   'São Paulo'
};
return msg;

